using UnityEngine; using UnityEngine.InputSystem; public class BackroomsFlashlight : MonoBehaviour { [SerializeField] private Light flashlight; [SerializeField] private bool startEnabled = true; private void Start(){ if (flashlight == null) flashlight = GetComponent<Light>(); if (flashlight != null) flashlight.enabled = startEnabled; } private void Update(){ if (Keyboard.current != null && Keyboard.current.fKey.wasPressedThisFrame && flashlight != null) flashlight.enabled = !flashlight.enabled; } }